mapper.select:
SELECT POS_CD, POS_NM, POS_LVL, USE_YN, REG_DTM FROM POSITION_MST
AND USE_YN = #{useYn}
ORDER BY POS_LVL

mapper.update:
	UPDATE POSITION_MST
  SET 
  	POS_NM = #{posNm},
      POS_LVL = #{posLvl},
      USE_YN = #{useYn}
  WHERE POS_CD = #{posCd}

	UPDATE POSITION_MST
  SET USE_YN = 'N'
  WHERE POS_CD = #{posCd}

