DELETE FROM EMP_ROLE
WHERE EMP_NO = #{empNo}
  AND ROLE_CD = #{roleCd}

mapper.update:
UPDATE ACCESS_LOG
SET
	LOGOUT_DTM = SYSTIMESTAMP,
	LOGOUT_REASON = #{logoutReason}
WHERE ACCESS_LOG_NO = #{accessLogNo}
  AND LOGOUT_DTM IS NULL

UPDATE ACCESS_LOG
SET
	AUTH_CHANNEL = #{authChannel},
	TOKEN_JTI = #{tokenJti},
	TOKEN_EXP_DTM = #{tokenExpDtm}
WHERE ACCESS_LOG_NO = #{accessLogNo}
